/*@ Import Coq Require Import gcd_iterative */

int gcd_iterative(int a, int b)
/*@ Require
      0 <= a &&
      0 <= b &&
      (a != 0 || b != 0) &&
      emp
    Ensure
      gcd_iterative_spec(a@pre, b@pre, __return) && emp
*/
{
    int r;

    /*@ Assert exists a0 b0,
          a0 == a@pre &&
          b0 == b@pre &&
          a == a0 &&
          b == b0 &&
          emp
    */
    while (b != 0)
    /*@ Inv exists a0 b0 g,
          a0 == a@pre &&
          b0 == b@pre &&
          0 <= a &&
          0 <= b &&
          (a != 0 || b != 0) &&
          gcd_iterative_spec(a0, b0, g) &&
          gcd_iterative_spec(a, b, g) &&
          emp
    */
    {
        r = a % b;
        a = b;
        b = r;
    }

    /*@ Assert gcd_iterative_spec(a@pre, b@pre, a) && emp */
    return a;
}

