int sum_to_n(int n)
/*@ Require
      0 <= n &&
      INT_MIN <= n * (n + 1) / 2 &&
      n * (n + 1) / 2 <= INT_MAX &&
      emp
    Ensure
      __return == n@pre * (n@pre + 1) / 2 && emp
*/
{
    int i;
    int ret = 0;

    /*@ Inv
          1 <= i && i <= n + 1 &&
          n == n@pre &&
          ret == (i - 1) * i / 2
    */
    for (i = 1; i <= n; ++i) {
        ret += i;
    }

    /*@ Assert
          i == n + 1 &&
          n == n@pre &&
          ret == n * (n + 1) / 2
    */
    return ret;
}

